305	24f6aaee-2445-4d31-91c7-54523e52b860	35189281-e4ed-4b9f-a121-6fe3b8d2e24a	[MM01_-_Malzeme_Yaratma.pptx | Slayt 11/13]\nBAŞLIK: MM01 - Malzeme Yaratma\nSeçilen kalite kontrol türünün sistemde fiilen devreye girmesini sağlar. Bu onay sayesinde üretim tamamlanıp depoya giriş yapıldığında, sistem otomatik olarak bir "Kalite Muayene Lotu" oluşturarak malzemeyi kalite departmanı onay verene kadar bloke (kullanılamaz) stokta tutar.	Sayfa 11	11	6634775,4141925,8726375,4936025	all-MiniLM-L6-v2	0	\N	2026-04-14T08:54:56.418567+00:00	{"bbox": "6634775,4141925,8726375,4936025", "page": 11, "type": "pptx_callout", "source": "MM01_-_Malzeme_Yaratma.pptx", "shape_id": "327", "file_type": "pptx", "image_path": "C:\\\\Users\\\\fatih.tekin\\\\.gemini\\\\antigravity\\\\scratch\\\\proje001\\\\backend\\\\temp_uploads\\\\images_MM01_-_Malzeme_Yaratma\\\\page_11.png", "sql_doc_id": "24f6aaee-2445-4d31-91c7-54523e52b860", "chunk_index": 4, "slide_emu_h": 5143500, "slide_emu_w": 9144000, "target_bbox": "", "total_pages": 13, "sqlite_doc_id": "24f6aaee-2445-4d31-91c7-54523e52b860", "slide_chunk_group": "MM01_-_Malzeme_Yaratma.pptx::slide11"}	[-0.004096601,0.08596717,0.011690687,0.0035693315,-0.09678624,-0.0053246077,0.084547654,0.07425792,-0.021457937,-0.08153481,-0.028018715,0.01305158,-0.043130275,-0.04045069,-0.017357377,0.0004189147,-0.024043638,0.0758395,-0.04714376,-0.05779985,0.024212522,0.029568154,0.039237283,-0.013325452,-0.004181823,-0.0027487518,-0.012007805,0.04478583,0.036987174,-0.06663077,0.07061773,0.070247054,-0.03309819,-0.010519894,0.002186434,0.058539424,-0.054523055,-0.027772335,-0.003790219,0.029503193,0.027076105,-0.049731012,-0.09527169,-0.008744638,-0.033148862,-0.027587965,-0.10445084,0.012969264,0.011459494,0.034136586,-0.10962493,-0.03235972,-0.07783297,-0.025493678,0.026048755,-0.13189241,0.002334169,0.07125761,0.009072438,-0.0020344146,-0.0033163363,0.061296474,0.003249758,-0.0032595852,-0.013678114,-0.07124039,0.005003747,-0.00066260766,0.0045221974,-0.0417